  /** LIKE-шаблон userId в таблице creators для пользователей одного дочернего бота (совпадает с ключами saveDBUser в инвест / PR / реф / ОС / обменник). */
  function childCreatorsUserIdLikePattern(template, tokenOrHash) {
      const h = String(tokenOrHash || "").includes(":") ? String(tokenOrHash).split(":")[0] : String(tokenOrHash);
      const t = String(template || "").toLowerCase();
      if (t.includes("pr") || t.includes("пиар")) return `pr_u_pr_${h}_%`;
      if (t.includes("ref") || t.includes("реф")) return `ref_u_ref_${h}_%`;
      if (t.includes("feedback") || t.includes("обратн") || t.includes("✉️")) return `fb_u_${h}_%`;
      if (t.includes("exchange") || t.includes("обмен")) return `inv_u_ex_${h}_%`;
      return `inv_u_${h}_%`;
  }

  async function countChildUsersForBot(db, template, token) {
      try {
          const row = await db.prepare("SELECT COUNT(*) as c FROM creators WHERE userId LIKE ?")
              .bind(childCreatorsUserIdLikePattern(template, token)).first();
          return row && row.c != null ? Number(row.c) : 0;
      } catch (e) { return 0; }
  }

  /** Разбор callback вида prefix + PARAM + _ + globalId (PARAM может содержать _). */
  function parseCfgCallbackData(prefix, cbData) {
      if (!cbData || !cbData.startsWith(prefix)) return null;
      const rest = cbData.slice(prefix.length);
      const i = rest.lastIndexOf("_");
      if (i <= 0) return null;
      return { param: rest.slice(0, i), gId: rest.slice(i + 1) };
  }

