    async processBroadcastQueue(env) {
    const db = env.DB || env.D1;
    const { results } = await db.prepare("SELECT id, bot_token, user_id, message, from_chat_id, msg_id, has_media, keyboard FROM broadcast_queue WHERE status = 'pending' LIMIT 30").all();
    
    if (!results || results.length === 0) return;

    for (const row of results) {
        try {
            const kb = row.keyboard ? JSON.parse(row.keyboard) : null;
            if (row.has_media && row.from_chat_id && row.msg_id) {
                const payload = { chat_id: row.user_id, from_chat_id: row.from_chat_id, message_id: parseInt(row.msg_id) };
                if (kb) payload.reply_markup = kb;
                await fetch(`https://api.telegram.org/bot${row.bot_token}/copyMessage`, {
                    method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload)
                });
            } else {
                const payload = { chat_id: row.user_id, text: row.message || "", parse_mode: "HTML" };
                if (kb) payload.reply_markup = kb;
                await fetch(`https://api.telegram.org/bot${row.bot_token}/sendMessage`, {
                    method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload)
                });
            }
            await db.prepare("UPDATE broadcast_queue SET status = 'sent' WHERE id = ?").bind(row.id).run();
        } catch (e) {
            await db.prepare("UPDATE broadcast_queue SET status = 'error' WHERE id = ?").bind(row.id).run();
        }
    }
},

