            const hours = String(moscowTime.getUTCHours()).padStart(2, '0');
            const minutes = String(moscowTime.getUTCMinutes()).padStart(2, '0');
            const currentTimeStr = `${hours}:${minutes}`;
            const currentDateStr = `${moscowTime.getUTCFullYear()}-${moscowTime.getUTCMonth()}-${moscowTime.getUTCDate()}`;

            if (currentTimeStr !== targetTime) return; // Срабатывает только в нужную минуту
            if (sys.config.last_summary_date === currentDateStr) return; // Уже отправляли сегодня

