                if (listings.length === 0) return await this.editMsg(chatId, messageId, "📭 <b>На рынке пока нет ботов.</b>", token, { inline_keyboard: [[{text:"⬅️ Назад", callback_data:"market_main"}]] });

                const item = listings[page];
                if (!item) return await this.alert(callbackId, "Страница не найдена", token);

                const sellerStats = marketData.stats[item.sellerId] || { success: 0, fail: 0 };
                const totalTrades = sellerStats.success + sellerStats.fail;
                const rating = totalTrades > 0 ? Math.round((sellerStats.success / totalTrades) * 100) : 0;

                const botInfo = await env.DB.prepare("SELECT * FROM managed_bots WHERE globalId = ?").bind(item.botGlobalId).first();
