                if (page < listings.length - 1) navRow.push({ text: "След. ▶️", callback_data: `market_buy_list_${page + 1}` });
                if (navRow.length > 0) kb.inline_keyboard.push(navRow);
                kb.inline_keyboard.push([{ text: "⬅️ Назад", callback_data: "market_main" }]);

                return await this.editMsg(chatId, messageId, msg, token, kb);
