                if (tIdx === -1) return await this.alert(callbackId, "Сделка не найдена", token);
                
                const trade = marketData.trades[tIdx];
                if (trade.buyerId !== String(userId)) return new Response("OK");

                const sellerKey = trade.sellerId;
                let sellerUser = await this.getDBUser(sellerKey, env);
                if (sellerUser) {
                    const fee = trade.price * 0.01;
                    const net = trade.price - fee;
                    sellerUser.balance += net;
                    if (!sellerUser.txHistory) sellerUser.txHistory = [];
                    sellerUser.txHistory.push({ date: Date.now(), amount: net, desc: `Успешная продажа бота #${trade.botGlobalId} (комиссия 1%)` });
                    await this.saveDBUser(sellerKey, sellerUser, env);
                    try { await this.sendMsg(sellerKey, `🤝 <b>Сделка завершена!</b>\nПокупатель подтвердил получение.\nНа ваш баланс зачислено ${net.toFixed(2)}₽ (комиссия 1%).`, token); } catch(e){}
                }

                // ОБНОВЛЕНИЕ РЕЙТИНГА ПРОДАВЦА
                if (!marketData.stats) marketData.stats = {};
