                    const payUrl = `https://yoomoney.ru/quickpay/confirm.xml?receiver=${wallet}&quickpay-form=shop&targets=Пополнение+баланса&sum=${amount}&label=${userId}&paymentType=AC`;

                    user.state = "idle";
