                    const minW = sysData.config.minWithdraw || 50;
                    const amount = parseFloat(text.replace(',', '.'));
                    const refBal = Number(user.refBalance || user.ref_balance || 0);

                    if (isNaN(amount) || amount < minW) return await this.sendMsg(chatId, `❌ Минимум: ${minW} ₽. Введите заново:`, token);
                    if (amount > refBal) return await this.sendMsg(chatId, `❌ Недостаточно средств на балансе. Доступно: ${refBal.toFixed(2)} ₽.`, token);
                    
                    user.tempCrWithdraw = amount;
