                    if (user.refBalance !== undefined) user.refBalance -= amount;
                    else if (user.ref_balance !== undefined) user.ref_balance -= amount;
                    
                    user.state = "idle";
                    delete user.tempCrWithdraw;
                    await this.saveDBUser(userId, user, env);

                    const reqId = Date.now().toString();
                    const reqData = { type: "creator_withdraw", userId: String(userId), sum: amount, wallet: reqs, date: Date.now() };
                    await env.DB.prepare("INSERT INTO requests (id, data) VALUES (?, ?)").bind(reqId, JSON.stringify(reqData)).run();

                    const dateStr = new Date().toLocaleString('ru-RU', { timeZone: 'Europe/Moscow' });
