                        if(!newOwnerUser.bots) newOwnerUser.bots = [];
                        newOwnerUser.bots.push(botToTransfer); 
                        
                        await env.DB.prepare("UPDATE managed_bots SET ownerId = ? WHERE globalId = ?").bind(newOwnerId, gId).run();
                        await this.saveDBUser(userId, user, env);
                        await this.saveDBUser(newOwnerId, newOwnerUser, env);
                        
                        user.state = "idle"; await this.saveDBUser(userId, user, env);
                        try { await this.sendMsg(newOwnerId, `💌 <b>Вам передан бот #${gId} (@${botToTransfer.username}) от пользователя ${userId}!</b>\nЗайдите в "Мои боты", чтобы увидеть его.`, token); } catch(e){}
                        return await this.sendMsg(chatId, "✅ Бот успешно передан новому владельцу! Пользователь получил уведомление.", token, { inline_keyboard: [[{text:"⬅️ К списку ботов", callback_data:"my_bots_page_0"}]]});
