                            const hpNew = Number(sysHost.config?.hostPrice) || 17;
                            const freeHostingBal = hpNew * (24 / 720);
                            const botObj = { 
                                globalId: newGlobalId, 
                                username: botInfo.username,
                                botUsername: botInfo.username,
                                token: text,
                                template: templateName,
                                status: 'on',
                                enabled: true,
                                hostingBalance: 0, // 🔥 24 ЧАСА БЕСПЛАТНО
                                lastDeducted: Date.now()
                            };
                            user.bots.push(botObj);

                            await this.saveDBUser(userId, user, env);

                            const cfgA = sysHost.config || {};
