return await this.editMsg(chatId, msgId, `💰 <b>Пополнение через ${methodText}</b>\n\n${methodDetails}\n\n📝 <b>Введите сумму пополнения в ${CONFIG.CURRENCY}:</b>\n(минимальная сумма: ${minRep})`, token, { inline_keyboard: [[{text:"⬅️ Назад", callback_data:"dep_topup"}]] });
