          if (botConfig.START_DATE) {
              const parts = botConfig.START_DATE.split('.');
              if (parts.length === 3) startDate = new Date(`${parts[2]}-${parts[1]}-${parts[0]}`);
          }
          const days = Math.ceil(Math.abs(Date.now() - startDate.getTime()) / 86400000);
          let today = 0; let totalWith = 0; const todayStart = new Date().setHours(0,0,0,0);
          allUsers.forEach(r => {
              try {
                  const u = JSON.parse(r.data);
                  if (u.createdAt > todayStart) today++;
                  totalWith += Number(u.withdrawn || u.totalWithdrawn || 0);
              } catch(e) {}
          });
