  // =============================================
  // ОБРАБОТКА ВВОДА СУММЫ ВЫВОДА
  // =============================================
if (user.state === "wait_withdraw_amount" && text) {
    const amount = parseFloat(text.replace(',', '.'));
    const method = user.selectedWithdrawMethod;
    const minSum = method === "crypto" ? (botConfig.MIN_CRYP_SUM || 50) : (botConfig.MIN_WITHDRAW || 50);
    const cur = botConfig.CURRENCY || "₽";
    
    if (isNaN(amount) || amount < minSum) {
        return await this.sendMsg(chatId, `❌ <b>Ошибка!</b>\nМинимальная сумма: ${minSum} ${cur}\nВведите сумму снова:`, token, { inline_keyboard: [[{ text: "⬅️ Отмена", callback_data: "pr_withdraw" }]] });
    }
    if (amount > user.balance) return await this.sendMsg(chatId, `❌ <b>Недостаточно средств!</b> Доступно: ${user.balance.toFixed(2)} ${cur}`, token);

    let commission = 0;
    if (method === "crypto_bot") commission = 3; // Комиссия на вывод CryptoBot
    
    const commissionAmount = amount * (commission / 100);
    const netAmount = amount - commissionAmount;

    let methodText = "Система вывода";
    if (method === "azvoks") methodText = "Азвокс";
    if (method === "yoomoney") methodText = "Юмани";
    if (method === "crypto_bot") methodText = "Крипто бот";
    if (method === "sbp") methodText = "СБП";
    if (method === "crypto") methodText = "Криптовалюта";
    
    let withdrawText = 
        `💸 <b>Подтверждение вывода</b>\n\n` +
        `├ Способ: ${methodText}\n` +
        `├ Реквизиты: ${user.withdrawDetails.details}\n` +
        `├ Запрошено: ${amount.toFixed(2)} ${cur}\n`;
        
    // Показываем комиссию ТОЛЬКО для криптобота
    if (method === "crypto_bot" && commission > 0) {
        withdrawText += `├ Комиссия (${commission}%): ${commissionAmount.toFixed(2)} ${cur}\n`;
    }
    
    withdrawText += `└ К получению: <b>${netAmount.toFixed(2)} ${cur}</b>\n\n` +
        `✅ <b>Для подтверждения нажмите "Подтвердить вывод"</b>`;
    
    user.pendingWithdraw = { amount, commission: commissionAmount, netAmount, method: methodText, details: user.withdrawDetails.details, timestamp: Date.now() };
    user.state = "wait_withdraw_confirmation";
    await this.saveDBUser(userKey, user, env);
    
    return await this.sendMsg(chatId, withdrawText, token, {
        inline_keyboard: [[{ text: "✅ Подтвердить вывод", callback_data: "pr_confirm_withdraw" }, { text: "❌ Отменить", callback_data: "pr_withdraw" }]]
    });
  }
  
// =============================================
  // ПОДТВЕРЖДЕНИЕ ВЫВОДА (СОЗДАНИЕ ЗАЯВКИ)
