                const refBonus1 = payment.amount * (depP1 / 100);
                ref1User.balance = (Number(ref1User.balance) || 0) + refBonus1;
                ref1User.earnedFromRefs = (Number(ref1User.earnedFromRefs) || 0) + refBonus1;
                await this.saveDBUser(ref1Key, ref1User, env);
