                        ref2User.balance = (Number(ref2User.balance) || 0) + refBonus2;
                        ref2User.earnedFromRefs = (Number(ref2User.earnedFromRefs) || 0) + refBonus2;
                        await this.saveDBUser(ref2Key, ref2User, env);
