  // Функция для отправки сообщений
  async function sendMsg(chatId, text, token, keyboard = null, parseMode = "HTML") {
    try {
        const payload = {
            chat_id: chatId,
            text: text,
            parse_mode: parseMode
        };
        
        if (keyboard) {
            payload.reply_markup = keyboard;
        }
        
        const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(payload)
        });
        
        const result = await response.json();
        if (!result.ok) {
            console.error(`❌ Ошибка отправки сообщения: ${result.description}`);
        }
        return result;
    } catch (error) {
        console.error(`❌ Ошибка при отправке сообщения: ${error.message}`);
        return null;
    }
  }
  
  // Функция для редактирования сообщений
  async function editMsg(chatId, messageId, text, token, keyboard = null, parseMode = "HTML") {
    try {
        const payload = {
            chat_id: chatId,
            message_id: messageId,
            text: text,
            parse_mode: parseMode
        };
        
        if (keyboard) {
            payload.reply_markup = keyboard;
        }
        
        const response = await fetch(`https://api.telegram.org/bot${token}/editMessageText`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(payload)
        });
        
        const result = await response.json();
        if (!result.ok) {
            console.error(`❌ Ошибка редактирования сообщения: ${result.description}`);
        }
        return result;
    } catch (error) {
        console.error(`❌ Ошибка при редактировании сообщения: ${error.message}`);
        return null;
    }
  }
  
