    let subCount = 0;
    try {
        let fetchChannel = postsChannel;
        if (!fetchChannel.startsWith('@') && !fetchChannel.startsWith('-100')) fetchChannel = '@' + fetchChannel;
        const res = await fetch(`https://api.telegram.org/bot${token}/getChatMemberCount?chat_id=${fetchChannel}`).then(r=>r.json());
        if (res.ok) subCount = res.result;
    } catch(e){}
    const pinRatio = botConfig.PIN_RATIO || 0.5;
